public class PriorityQueueOps {

    public static int priorityQueueOps(int[] arr) {
        if (arr.length == 0) return 0;

        List<Integer> heap = new ArrayList<>();

        int opCount = arr[0];
        int idx = 1;
        int total = 0;

        for (int i = 0; i < opCount; i++) {
            int type = arr[idx];
            int val = arr[idx + 1];
            idx += 2;
            if (type == 1) {
                heap.add(val);
                int j = heap.size() - 1;
                while (j > 0) {
                    int p = (j - 1) / 2;
                    if (heap.get(j) < heap.get(p)) {
                        int tmp = heap.get(j); heap.set(j, heap.get(p)); heap.set(p, tmp);
                        j = p;
                    } else break;
                }
            } else if (type == 2) {
                if (heap.isEmpty()) continue;
                total += heap.get(0);
                heap.set(0, heap.get(heap.size() - 1));
                heap.remove(heap.size() - 1);
                int j = 0;
                while (true) {
                    int s = j, l = 2 * j + 1, r = 2 * j + 2;
                    if (l < heap.size() && heap.get(l) < heap.get(s)) s = l;
                    if (r < heap.size() && heap.get(r) < heap.get(s)) s = r;
                    if (s != j) {
                        int tmp = heap.get(j); heap.set(j, heap.get(s)); heap.set(s, tmp);
                        j = s;
                    } else break;
                }
            }
        }
        return total;
    }
}

fun priorityQueueOps(arr: IntArray): Int {
    if (arr.isEmpty()) return 0
    val heap = mutableListOf<Int>()
    val opCount = arr[0]
    var idx = 1
    var total = 0

    fun siftUp(idx: Int) {
        var i = idx
        while (i > 0) { val p = (i-1)/2; if (heap[i] < heap[p]) { val t = heap[i]; heap[i] = heap[p]; heap[p] = t; i = p } else break }
    }
    fun siftDown(idx: Int) {
        var i = idx
        while (true) { var s = i; val l = 2*i+1; val r = 2*i+2
            if (l < heap.size && heap[l] < heap[s]) s = l
            if (r < heap.size && heap[r] < heap[s]) s = r
            if (s != i) { val t = heap[i]; heap[i] = heap[s]; heap[s] = t; i = s } else break }
    }

    for (i in 0 until opCount) {
        val type = arr[idx]; val v = arr[idx+1]; idx += 2
        if (type == 1) { heap.add(v); siftUp(heap.size - 1) }
        else if (type == 2) {
            if (heap.isEmpty()) continue
            total += heap[0]; heap[0] = heap[heap.size-1]; heap.removeAt(heap.size-1)
            if (heap.isNotEmpty()) siftDown(0)
        }
    }
    return total
}

def priority_queue_ops(arr: list[int]) -> int:
    if not arr:
        return 0

    heap: list[int] = []

    def sift_up(i: int) -> None:
        while i > 0:
            p = (i - 1) // 2
            if heap[i] < heap[p]:
                heap[i], heap[p] = heap[p], heap[i]
                i = p
            else:
                break

    def sift_down(i: int) -> None:
        size = len(heap)
        while True:
            s = i
            l, r = 2 * i + 1, 2 * i + 2
            if l < size and heap[l] < heap[s]:
                s = l
            if r < size and heap[r] < heap[s]:
                s = r
            if s != i:
                heap[i], heap[s] = heap[s], heap[i]
                i = s
            else:
                break

    def insert(val: int) -> None:
        heap.append(val)
        sift_up(len(heap) - 1)

    def extract_min() -> int:
        if not heap:
            return 0
        val = heap[0]
        heap[0] = heap[-1]
        heap.pop()
        if heap:
            sift_down(0)
        return val

    op_count = arr[0]
    idx = 1
    total = 0
    for _ in range(op_count):
        op_type = arr[idx]
        val = arr[idx + 1]
        idx += 2
        if op_type == 1:
            insert(val)
        elif op_type == 2:
            total += extract_min()

    return total

pub fn priority_queue_ops(arr: &[i32]) -> i32 {
    if arr.is_empty() { return 0; }

    let mut heap: Vec<i32> = Vec::new();
    let op_count = arr[0] as usize;
    let mut idx = 1;
    let mut total: i32 = 0;

    fn sift_up(heap: &mut Vec<i32>, mut i: usize) {
        while i > 0 {
            let p = (i - 1) / 2;
            if heap[i] < heap[p] { heap.swap(i, p); i = p; }
            else { break; }
        }
    }

    fn sift_down(heap: &mut Vec<i32>, mut i: usize) {
        let sz = heap.len();
        loop {
            let mut s = i;
            let l = 2 * i + 1;
            let r = 2 * i + 2;
            if l < sz && heap[l] < heap[s] { s = l; }
            if r < sz && heap[r] < heap[s] { s = r; }
            if s != i { heap.swap(i, s); i = s; }
            else { break; }
        }
    }

    for _ in 0..op_count {
        let t = arr[idx];
        let v = arr[idx + 1];
        idx += 2;
        if t == 1 {
            heap.push(v);
            sift_up(&mut heap, heap.len() - 1);
        } else if t == 2 {
            if heap.is_empty() { continue; }
            total += heap[0];
            let last = heap.len() - 1;
            heap[0] = heap[last];
            heap.pop();
            if !heap.is_empty() { sift_down(&mut heap, 0); }
        }
    }
    total
}

object PriorityQueueOps {

  def priorityQueueOps(arr: Array[Int]): Int = {
    if (arr.isEmpty) return 0
    val heap = scala.collection.mutable.ArrayBuffer[Int]()
    val opCount = arr(0)
    var idx = 1
    var total = 0

    def siftUp(idx: Int): Unit = {
      var i = idx
      while (i > 0) { val p = (i-1)/2; if (heap(i) < heap(p)) { val t = heap(i); heap(i) = heap(p); heap(p) = t; i = p } else return }
    }
    def siftDown(idx: Int): Unit = {
      var i = idx; var cont = true
      while (cont) { var s = i; val l = 2*i+1; val r = 2*i+2
        if (l < heap.size && heap(l) < heap(s)) s = l
        if (r < heap.size && heap(r) < heap(s)) s = r
        if (s != i) { val t = heap(i); heap(i) = heap(s); heap(s) = t; i = s } else cont = false }
    }

    for (_ <- 0 until opCount) {
      val tp = arr(idx); val v = arr(idx+1); idx += 2
      if (tp == 1) { heap += v; siftUp(heap.size - 1) }
      else if (tp == 2) {
        if (heap.isEmpty) {}
        else { total += heap(0); heap(0) = heap(heap.size-1); heap.remove(heap.size-1); if (heap.nonEmpty) siftDown(0) }
      }
    }
    total
  }
}

