    func siftDown(_ idx: Int) {
        var i = idx
        while true { var s = i; let l = 2*i+1, r = 2*i+2
            if l < heap.count && heap[l] < heap[s] { s = l }
            if r < heap.count && heap[r] < heap[s] { s = r }
